const fs = require('fs');

const file = fs.readFileSync('src/app/page.tsx', 'utf-8');

function extractBetween(str, start, end) {
    const i = str.indexOf(start);
    if (i === -1) return null;
    const startIdx = i;
    const suffix = str.substring(startIdx + start.length);
    const j = suffix.indexOf(end);
    if (j === -1) return null;
    return str.substring(startIdx, startIdx + start.length + j);
}

const authModal = extractBetween(file, '// ÔöÇÔöÇÔöÇ Auth Modal (Login / Register)', 'function HeroDynamic');
const heroDynamic = extractBetween(file, 'function HeroDynamic', '// ÔöÇÔöÇÔöÇ Typewriter effect');
const typewriter = extractBetween(file, '// ÔöÇÔöÇÔöÇ Typewriter effect', '// ÔöÇÔöÇÔöÇ Logo3D');
const logo3d = extractBetween(file, '// ÔöÇÔöÇÔöÇ Logo3D', '// ÔöÇÔöÇÔöÇ ProductCard');
const productCard = extractBetween(file, '// ÔöÇÔöÇÔöÇ ProductCard', '// ÔöÇÔöÇÔöÇ VariantConfigurator');
const variantConfig = file.substring(file.indexOf('// ÔöÇÔöÇÔöÇ VariantConfigurator'));

const heroSlideType = extractBetween(file, 'interface HeroSlide {', 'interface Category {');

const importsBase = `import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { cldOpt } from '@/lib/utils';
`;

fs.writeFileSync('src/components/AuthModal.tsx', `import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Lock, Mail, UserPlus } from 'lucide-react';
import { useAuth } from '@/context/AuthContext';

export ` + authModal.substring(authModal.indexOf('function AuthModal')));

fs.writeFileSync('src/components/Typewriter.tsx', `import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';

export ` + typewriter.substring(typewriter.indexOf('function Typewriter')));

fs.writeFileSync('src/components/Logo3D.tsx', `import React, { useRef, useEffect } from 'react';
import { motion } from 'framer-motion';
import { cldOpt } from '@/lib/utils';

export ` + logo3d.substring(logo3d.indexOf('function Logo3D')));

fs.writeFileSync('src/components/HeroDynamic.tsx', `import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import { cldOpt } from '@/lib/utils';
import { Typewriter } from './Typewriter';
import { Logo3D } from './Logo3D';

export ` + heroSlideType + `

export ` + heroDynamic.trim());

fs.writeFileSync('src/components/ProductCard.tsx', `import React, { memo, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Minus, Plus, ShoppingCart, Check } from 'lucide-react';
import { Product } from '@/context/CartContext';
import { cldOpt } from '@/lib/utils';

export ` + productCard.substring(productCard.indexOf('const ProductCard')));

fs.writeFileSync('src/components/VariantConfigurator.tsx', `import React, { useState } from 'react';
import { Minus, Plus, Check } from 'lucide-react';
import { Product } from '@/context/CartContext';

export ` + variantConfig.substring(variantConfig.indexOf('function VariantConfigurator')));

let newPage = file.substring(0, file.indexOf('// ÔöÇÔöÇÔöÇ Auth Modal (Login / Register)'));

// remove cldOpt
const cldOptImpl = extractBetween(newPage, '// ÔöÇÔöÇÔöÇ Cloudinary image optimizer', '// ÔöÇÔöÇÔöÇ Apply dynamic theme to document');
newPage = newPage.replace(cldOptImpl, '');

// remove HeroSlide interface
const heroSlideTypeRemoval = extractBetween(newPage, 'interface HeroSlide', 'interface Category');
newPage = newPage.replace(heroSlideTypeRemoval, '');

const newImports = `import { cldOpt } from '@/lib/utils';
import { AuthModal } from '@/components/AuthModal';
import { HeroDynamic, HeroSlide } from '@/components/HeroDynamic';
import { Typewriter } from '@/components/Typewriter';
import { Logo3D } from '@/components/Logo3D';
import { ProductCard } from '@/components/ProductCard';
import { VariantConfigurator } from '@/components/VariantConfigurator';

`;
newPage = newPage.replace("import autoTable from 'jspdf-autotable';\n", "import autoTable from 'jspdf-autotable';\n" + newImports);

// Fix trailing bracket that could be lost
if (!newPage.trim().endsWith('}')) {
    newPage += '}\n';
}

fs.writeFileSync('src/app/page.tsx', newPage);

console.log('Extraction complete');

'use client';

import React, { useEffect, useState, useCallback, useRef, useMemo, memo } from 'react';
import { collection, getDocs, query, orderBy, doc, getDoc } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { Product, useCart } from '@/context/CartContext';
import { useAuth } from '@/context/AuthContext';
import {
  ShoppingCart, Search, ChevronLeft, ChevronRight,
  Minus, Plus, Trash2, X, Package, Home, Grid3X3, Check,
  User, LogOut, Mail, Lock, UserPlus, Menu, FileText, Info, Filter,
  Sparkles, Flame, Tag, Star, Box, Gem, Zap, ShieldCheck, Calendar, Rocket, LayoutGrid
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { cldOpt } from '@/lib/utils';
import { AuthModal } from '@/components/AuthModal';
import { HeroDynamic, HeroSlide } from '@/components/HeroDynamic';
import { Typewriter } from '@/components/Typewriter';
import { Logo3D } from '@/components/Logo3D';
import { ProductCard } from '@/components/ProductCard';
import { VariantConfigurator } from '@/components/VariantConfigurator';


// ÔöÇÔöÇÔöÇ Apply dynamic theme to document (called from both localStorage cache and Firebase) ÔöÇÔöÇ
function applyThemeToDoc(t: { primary?: string; accent?: string; bg?: string; gradient?: string | null }) {
  const p = t.primary || '#0a0a0a';
  const a = t.accent || '#00b4d8';
  const bg = t.bg || '#f8f8f8';

  document.getElementById('altos-theme')?.remove();
  const styleEl = document.createElement('style');
  styleEl.id = 'altos-theme';
  styleEl.textContent = `
    /* ÔöÇÔöÇ Altos Dynamic Theme ÔöÇÔöÇ */
    :root { --black:${p};--black-2:${p};--black-3:${p};--bg:${bg};--accent:${a}; }
    .altos-hero { background: ${t.gradient || p} !important; }
    header { border-bottom-color: ${p}22 !important; }
    .bg-\\[\\#0a0a0a\\], .bg-\\[\\#0d1b2a\\] { background-color: ${p} !important; }
    .hover\\:bg-\\[\\#1e1e1e\\]:hover, .hover\\:bg-\\[\\#1b2e45\\]:hover { background-color: ${p}dd !important; }
    .cat-pill.active { background:${p}!important; border-color:${p}!important; }
    .altos-cat-active { background-color:${p}!important; border-color:${p}!important; color:#fff!important; }
    .bottom-nav { background:${p}ee !important; }
    .cart-header-bg { background:${p} !important; }
    body, .bg-\\[\\#f7f7f7\\] { background-color:${bg} !important; }
    .altos-marquee-band { background:${p} !important; }
    .text-\\[\\#00b4d8\\] { color:${a} !important; }
  `;
  document.head.appendChild(styleEl);
}

interface Category {
  id: string;
  name: string;
  order: number;
}

export default function Storefront() {
  const [products, setProducts] = useState<Product[]>([]);
  const [heroSlides, setHeroSlides] = useState<HeroSlide[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [currentSlide, setCurrentSlide] = useState(0);
  const [loading, setLoading] = useState(true);
  const [cartOpen, setCartOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState('Todos');
  const [logoUrl, setLogoUrl] = useState('/logo.jpg');
  const [logo2Url, setLogo2Url] = useState('');
  // Read cached theme from localStorage to avoid FOUC
  const [themeColors, setThemeColors] = useState(() => {
    try {
      const cached = typeof window !== 'undefined' ? localStorage.getItem('altos-theme-cache') : null;
      if (cached) return JSON.parse(cached);
    } catch { }
    return { primary: '#0a0a0a', accent: '#00b4d8', bg: '#f8f8f8', gradient: null as string | null };
  });
  const [authModalOpen, setAuthModalOpen] = useState(false);
  const [isLoginMode, setIsLoginMode] = useState(true);
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [selectedProductForModal, setSelectedProductForModal] = useState<Product | null>(null);
  const [authName, setAuthName] = useState('');
  const [authLoading, setAuthLoading] = useState(false);
  const [authError, setAuthError] = useState('');
  const [userMenuOpen, setUserMenuOpen] = useState(false);
  const [leftMenuOpen, setLeftMenuOpen] = useState(false);
  const [activeSection, setActiveSection] = useState<string | null>(null);
  const [activeSections, setActiveSections] = useState<string[]>([]);

  const { user, logout, loginWithEmail, registerWithEmail, loginWithGoogle } = useAuth();

  const handleAuthSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setAuthLoading(true);
    setAuthError('');
    try {
      if (isLoginMode) {
        await loginWithEmail(authEmail, authPassword);
      } else {
        await registerWithEmail(authEmail, authPassword, authName);
      }
      setAuthModalOpen(false);
      setAuthEmail('');
      setAuthPassword('');
      setAuthName('');
    } catch (err: any) {
      if (err.code === 'auth/invalid-credential') setAuthError('Credenciales incorrectas');
      else if (err.code === 'auth/email-already-in-use') setAuthError('El correo ya est├í registrado');
      else if (err.code === 'auth/weak-password') setAuthError('La contrase├▒a debe tener al menos 6 caracteres');
      else setAuthError('Ocurri├│ un error. Int├®ntalo de nuevo.');
    } finally {
      setAuthLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    setAuthLoading(true);
    setAuthError('');
    try {
      await loginWithGoogle();
      setAuthModalOpen(false);
    } catch (err: any) {
      setAuthError('Error al iniciar sesi├│n con Google');
    } finally {
      setAuthLoading(false);
    }
  };

  const { cart, cartCount, cartTotal, updateQuantity, removeFromCart,
    addToCart, calcItemPrice, clearCart } = useCart();

  // Apply theme immediately from localStorage (zero-flash)
  useEffect(() => {
    try {
      const cached = localStorage.getItem('altos-theme-cache');
      if (cached) {
        const t = JSON.parse(cached);
        applyThemeToDoc(t);
      }
    } catch { }
  }, []);

  useEffect(() => {
    const fetchAll = async () => {
      try {
        const [pSnap, hSnap, cSnap, brandingSnap, themeSnap, secSnap] = await Promise.all([
          getDocs(collection(db, 'productos')),
          getDocs(query(collection(db, 'heroCarousel'), orderBy('order', 'asc'))),
          getDocs(query(collection(db, 'categorias'), orderBy('order', 'asc'))),
          getDoc(doc(db, 'config', 'branding')),
          getDoc(doc(db, 'config', 'theme')),
          getDoc(doc(db, 'config', 'secciones')),
        ]);
        setProducts(pSnap.docs.map(d => ({ id: d.id, ...d.data() } as Product)));
        setHeroSlides(hSnap.docs.map(d => ({ id: d.id, ...d.data() } as HeroSlide)));
        setCategories(cSnap.docs.map(d => ({ id: d.id, ...d.data() } as Category)));
        // Load active sections
        if (secSnap.exists()) {
          setActiveSections(secSnap.data().active || []);
        } else {
          // Default: all sections active
          setActiveSections(['novedades', 'masVendidos', 'ofertas', 'destacados', 'mayoreo', 'piezasUnicas', 'remates', 'exclusivo', 'temporada', 'nuevos']);
        }
        if (brandingSnap.exists()) {
          const data = brandingSnap.data();
          if (data.logoUrl) setLogoUrl(data.logoUrl);
          if (data.logo2Url) setLogo2Url(data.logo2Url);
        }
        // Inject dynamic theme ÔÇö override Tailwind hardcoded colors via <style> tag
        if (themeSnap.exists()) {
          const t = themeSnap.data();
          const p = t.primary || '#0a0a0a';
          const a = t.accent || '#00b4d8';
          const bg = t.bg || '#f8f8f8';

          setThemeColors({ primary: p, accent: a, bg, gradient: t.gradient || null });

          // Cache in localStorage for instant next load (no FOUC)
          localStorage.setItem('altos-theme-cache', JSON.stringify({ primary: p, accent: a, bg, gradient: t.gradient || null }));

          // Remove old theme tag if exists
          applyThemeToDoc(t);
        }
      } catch (e) { console.error(e); }
      finally { setLoading(false); }
    };
    fetchAll();
  }, []);

  const handleDownloadPDF = async () => {
    setLoading(true);
    try {
      const doc = new jsPDF();

      // --- PORTADA SUPERIOR (Header Elegante) ---
      doc.setFillColor(15, 23, 42); // slate-900 oscuro premium
      doc.rect(0, 0, 210, 45, 'F');

      // Intentar cargar el logo actual
      let logoBase64 = null;
      if (logoUrl) {
        try {
          const res = await fetch(cldOpt(logoUrl, 150));
          const blob = await res.blob();
          logoBase64 = await new Promise((resolve) => {
            const reader = new FileReader();
            reader.onload = () => resolve(reader.result);
            reader.readAsDataURL(blob);
          });
        } catch (e) { console.error("Logo fetch error", e); }
      }

      if (logoBase64) {
        doc.addImage(logoBase64 as string, 'PNG', 14, 8, 28, 28);
      }

      doc.setTextColor(255, 255, 255);
      // @ts-ignore
      doc.setFont("helvetica", "bold");
      doc.setFontSize(26);
      doc.text('CAT├üLOGO MAYORISTA', logoBase64 ? 48 : 14, 22);

      // @ts-ignore
      doc.setFont("helvetica", "normal");
      doc.setFontSize(11);
      doc.setTextColor(200, 200, 200);
      doc.text('Altos - Especialistas en papeler├¡a y art├¡culos', logoBase64 ? 48 : 14, 30);

      const today = new Date().toLocaleDateString('es-MX', { year: 'numeric', month: 'long', day: 'numeric' });
      doc.setFontSize(9);
      doc.text(`Generado: ${today}`, 196, 30, { align: 'right' });

      let currentY = 55;

      // --- OBTENER IM├üGENES DE PRODUCTOS ---
      // Descargamos miniaturas muy ligeras para incrustarlas sin demorar mucho
      const imagesMap = new Map();
      const uniqueUrls = Array.from(new Set(products.map(p => p.imageUrl).filter(Boolean)));

      await Promise.all(uniqueUrls.map(async url => {
        try {
          const res = await fetch(cldOpt(url, 60)); // W=60 para optimizar carga
          const blob = await res.blob();
          const b64 = await new Promise((resolve) => {
            const reader = new FileReader();
            reader.onload = () => resolve(reader.result);
            reader.readAsDataURL(blob);
          });
          imagesMap.set(url, b64);
        } catch (e) { }
      }));

      // Agrupar productos por categor├¡a
      const categoriesMap = new Map<string, Product[]>();
      products.forEach(p => {
        const catName = p.category || 'Otros';
        if (!categoriesMap.has(catName)) categoriesMap.set(catName, []);
        categoriesMap.get(catName)!.push(p);
      });

      categoriesMap.forEach((catProducts, catName) => {
        if (currentY > 250) {
          doc.addPage();
          currentY = 20;
        }

        // T├¡tulo de categor├¡a con est├®tica minimalista
        doc.setFontSize(16);
        // @ts-ignore
        doc.setFont("helvetica", "bold");
        doc.setTextColor(15, 23, 42);
        doc.text(catName.toUpperCase(), 14, currentY);

        // Linea decorativa
        doc.setDrawColor(220, 220, 220);
        doc.setLineWidth(0.5);
        doc.line(14, currentY + 2, 196, currentY + 2);

        currentY += 8;

        const tableData = catProducts.map(p => [
          '', // Espacio para la foto
          p.sku ? `[${p.sku}]\n${p.name}` : p.name,
          `$${p.precioIndividual?.toFixed(2) || '0.00'}`,
          p.precioMayoreo > 0 ? `$${p.precioMayoreo.toFixed(2)}\n(${p.minMayoreo}+ pzs)` : '-',
          p.precioCaja > 0 ? `$${p.precioCaja.toFixed(2)}\n(${p.minCaja}+ caja)` : '-'
        ]);

        autoTable(doc, {
          startY: currentY,
          head: [['Foto', 'Art├¡culo', 'Menudeo', 'Mayoreo', 'Caja']],
          body: tableData,
          theme: 'plain',
          headStyles: {
            fillColor: [248, 250, 252],
            textColor: [71, 85, 105],
            fontStyle: 'bold',
            fontSize: 9,
            cellPadding: 4,
          },
          bodyStyles: {
            textColor: [15, 23, 42],
            fontSize: 9,
            valign: 'middle',
            cellPadding: 4,
          },
          alternateRowStyles: { fillColor: [252, 253, 254] },
          columnStyles: {
            0: { cellWidth: 20, halign: 'center' },
            1: { cellWidth: 80, fontStyle: 'bold' },
            2: { cellWidth: 25, halign: 'right' },
            3: { cellWidth: 28, halign: 'right' },
            4: { cellWidth: 28, halign: 'right' }
          },
          // Enganche para dibujar la imagen sobre la primera columna
          // @ts-ignore
          didDrawCell: (data) => {
            if (data.section === 'body' && data.column.index === 0) {
              const prod = catProducts[data.row.index];
              const b64 = prod.imageUrl ? imagesMap.get(prod.imageUrl) : null;
              if (b64) {
                const dim = 12; // Tama├▒o de la imagen
                const x = data.cell.x + (data.cell.width - dim) / 2;
                const y = data.cell.y + (data.cell.height - dim) / 2;
                doc.addImage(b64, 'PNG', x, y, dim, dim);
              }
            }
          }
        });

        currentY = (doc as any).lastAutoTable.finalY + 15;
      });

      // Paginaci├│n final a nivel documento
      const pageCount = (doc as any).internal.getNumberOfPages();
      for (let i = 1; i <= pageCount; i++) {
        doc.setPage(i);
        doc.setFontSize(8);
        doc.setTextColor(150, 150, 150);
        doc.text(`Cat├ílogo Oficial Altos - P├ígina ${i} de ${pageCount}`, doc.internal.pageSize.width / 2, doc.internal.pageSize.height - 10, { align: 'center' });
      }

      doc.save('Catalogo_Altos.pdf');
    } catch (e) {
      console.error("Error generating PDF", e);
      alert("Lo sentimos, ocurri├│ un error al generar el PDF. Verifica tu conexi├│n e intenta de nuevo.");
    } finally {
      setLoading(false);
    }
  };

  const nextSlide = useCallback(() => {
    if (heroSlides.length > 0) setCurrentSlide(p => (p + 1) % heroSlides.length);
  }, [heroSlides.length]);

  useEffect(() => {
    if (heroSlides.length <= 1) return;
    const t = setInterval(nextSlide, 4000);
    return () => clearInterval(t);
  }, [heroSlides.length, nextSlide]);

  const allCategories = ['Todos', ...categories.map(c => c.name)];

  const filtered = useMemo(() => {
    const query = searchQuery.toLowerCase();
    return products.filter(p => {
      const matchCat = activeCategory === 'Todos' || p.category === activeCategory;
      const matchSearch = p.name.toLowerCase().includes(query);
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const matchSection = !activeSection || ((p as any).sections || []).includes(activeSection);
      return matchCat && matchSearch && matchSection;
    });
  }, [products, activeCategory, searchQuery, activeSection]);

  const [displayCount, setDisplayCount] = useState(24);
  useEffect(() => {
    setDisplayCount(24);
  }, [activeCategory, searchQuery, activeSection]);

  const displayedProducts = filtered.slice(0, displayCount);

  const productGridContent = useMemo(() => (
    <div className="flex flex-col items-center">
      <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-4 md:gap-5 w-full">
        {displayedProducts.map((product, i) => (
          <ProductCard
            key={product.id}
            product={product}
            index={i}
            onAdd={(qty, variant) => addToCart(product, qty, variant)}
            onShowVariants={() => setSelectedProductForModal(product)}
          />
        ))}
      </div>

      {displayCount < filtered.length && (
        <button
          onClick={() => setDisplayCount(prev => prev + 24)}
          className="mt-12 bg-white border border-gray-200 text-gray-700 font-black text-sm px-8 py-3.5 rounded-2xl shadow-sm hover:border-gray-300 hover:bg-gray-50 transition-all flex items-center justify-center gap-2"
        >
          <Search size={16} className="text-[#00b4d8]" />
          Cargar m├ís art├¡culos ({filtered.length - displayCount} restantes)
        </button>
      )}
    </div>
  ), [displayedProducts, filtered.length, displayCount, addToCart]);

  const handleWhatsApp = () => {
    if (cart.length === 0) return;
    let text = `*PEDIDO ÔÇö ART├ìCULOS REDITUABLES*%0A%0A`;
    cart.forEach(item => {
      const price = calcItemPrice(item);
      text += `Ôû¬ *${item.name}* ├ù${item.quantity} ÔåÆ $${(price * item.quantity).toFixed(2)}%0A`;
    });
    text += `%0A*TOTAL: $${cartTotal.toFixed(2)}*%0A%0AHola, me gustar├¡a hacer este pedido.`;
    window.open(`https://wa.me/5215572177485?text=${text}`, '_blank');
  };

  return (
    <div className="min-h-screen flex flex-col">

      {/* ÔöÇÔöÇ HEADER ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      <header className="fixed top-0 left-0 right-0 z-50 bg-white/95 backdrop-blur-md border-b border-gray-100 shadow-sm">
        <div className="flex items-center justify-between px-5 md:px-10 h-16 max-w-screen-xl mx-auto w-full">

          {/* Men├║ y Logo */}
          <div className="flex items-center gap-4">
            {/* Bot├│n men├║ lateral */}
            <button
              onClick={() => setLeftMenuOpen(true)}
              className="text-gray-900 hover:text-gray-600 transition p-2 flex-shrink-0"
            >
              <Menu size={24} />
            </button>

            {/* Logo prominente */}
            <div className="flex items-center gap-3 flex-shrink-0">
              {/* eslint-disable-next-line @next/next/no-img-element */}
              <img
                src={cldOpt(logoUrl, 80) || '/logo.jpg'}
                alt="Altos"
                className="h-10 w-10 rounded-lg object-cover border border-gray-100 shadow-sm"
              />
              {logo2Url ? (
                <div className="flex items-center ml-1">
                  {/* eslint-disable-next-line @next/next/no-img-element */}
                  <img
                    src={cldOpt(logo2Url, 200)}
                    alt="Altos"
                    className="h-10 object-contain"
                  />
                </div>
              ) : (
                <div className="flex items-end relative pb-2 pr-4 ml-1">
                  <span className="text-[34px] text-gray-800 z-10 pl-1" style={{ fontFamily: 'var(--font-cursive)', fontWeight: 700, lineHeight: 0.8 }}>Altos</span>
                  {/* Underline */}
                  <div className="absolute bottom-[4px] left-0 right-0 h-[4.5px] bg-[#333] rounded-l-full"></div>
                  {/* Vertical stem */}
